72	func SessionIndexShardName(t time.Time) string {
73		if t.IsZero() {
74			t = time.Now().UTC()
75		}
76		return fmt.Sprintf("sessions-%04d-%02d.jsonl", t.UTC().Year(), t.UTC().Month())
77	}
