389	func SessionIndexShardFiles(logDir string, q SessionIndexQuery) ([]string, error) {
390		dir := SessionIndexDir(logDir)
391		entries, err := os.ReadDir(dir)
392		if os.IsNotExist(err) {
393			return nil, nil
394		}
395		if err != nil {
396			return nil, err
397		}
398		var files []string
399		for _, ent := range entries {
400			if ent.IsDir() {
401				continue
402			}
403			name := ent.Name()
404			if !strings.HasPrefix(name, "sessions-") || !strings.HasSuffix(name, ".jsonl") {
405				continue
406			}
407			if !sessionShardIntersects(name, q) {
408				continue
409			}
410			files = append(files, filepath.Join(dir, name))
411		}
412		sort.Sort(sort.Reverse(sort.StringSlice(files)))
413		return files, nil
414	}
