535	func sessionIndexEntryInRange(entry SessionIndexEntry, q SessionIndexQuery) bool {
536		if q.StartedAfter != nil && entry.StartedAt.Before(*q.StartedAfter) {
537			return false
538		}
539		if q.StartedBefore != nil && !entry.StartedAt.Before(*q.StartedBefore) {
540			return false
541		}
542		return true
543	}
