545	func sessionShardIntersects(name string, q SessionIndexQuery) bool {
546		month, ok := sessionShardMonth(name)
547		if !ok {
548			return false
549		}
550		next := month.AddDate(0, 1, 0)
551		if q.DefaultRecent && q.StartedAfter == nil && q.StartedBefore == nil {
552			now := time.Now().UTC()
553			current := time.Date(now.Year(), now.Month(), 1, 0, 0, 0, 0, time.UTC)
554			previous := current.AddDate(0, -1, 0)
555			return month.Equal(current) || month.Equal(previous)
556		}
557		if q.StartedAfter != nil && !next.After(*q.StartedAfter) {
558			return false
559		}
560		if q.StartedBefore != nil && !month.Before(*q.StartedBefore) {
561			return false
562		}
563		return true
564	}
