566	func sessionShardMonth(name string) (time.Time, bool) {
567		if len(name) != len("sessions-2006-01.jsonl") {
568			return time.Time{}, false
569		}
570		month, err := time.Parse("2006-01", strings.TrimSuffix(strings.TrimPrefix(name, "sessions-"), ".jsonl"))
571		if err != nil {
572			return time.Time{}, false
573		}
574		return month.UTC(), true
575	}
