635	func bodiesFromNativeLog(path string) (string, string) {
636		f, err := os.Open(path)
637		if err != nil {
638			return "", ""
639		}
640		defer f.Close()
641		var response, stderr string
642		scanner := bufio.NewScanner(f)
643		scanner.Buffer(make([]byte, 0, 64*1024), 16*1024*1024)
644		for scanner.Scan() {
645			var raw map[string]any
646			if err := json.Unmarshal(scanner.Bytes(), &raw); err != nil {
